        static int read_symlink_target_by_path(const eastl::string &path, eastl::string &target_path)
        {
            fs::vfile_tree_node *virtual_node = fs::k_vfs.get_virtual_node(path);
            if (virtual_node != nullptr && virtual_node->file_type == fs::FileTypes::FT_SYMLINK)
            {
                if (virtual_node->provider == nullptr)
                {
                    return -ENOENT;
                }
                target_path = virtual_node->provider->read_symlink_target();
                return target_path.empty() ? -ENOENT : 0;
            }

            char link_target[256];
            size_t link_len = 0;
            int read_ret = ext4_readlink(path.c_str(), link_target, sizeof(link_target) - 1, &link_len);
            if (read_ret != EOK)
            {
                return read_ret == ENOENT ? -ENOENT : -read_ret;
            }

            link_target[link_len] = '\0';
            target_path = link_target;
            return 0;
        }

        bool parse_proc_mount_namespace_path(const eastl::string &path, int &pid)
        {
            const char *prefix = "/proc/";
            const char *suffix = "/ns/mnt";
            size_t prefix_len = strlen(prefix);
            size_t suffix_len = strlen(suffix);
            if (path.length() <= prefix_len + suffix_len ||
                path.compare(0, prefix_len, prefix) != 0 ||
                path.compare(path.length() - suffix_len, suffix_len, suffix) != 0)
            {
                return false;
            }

            eastl::string id_part = path.substr(prefix_len, path.length() - prefix_len - suffix_len);
            if (id_part == "self")
            {
                proc::Pcb *current = proc::k_pm.get_cur_pcb();
                if (current == nullptr)
                {
                    return false;
                }
                pid = current->get_pid();
                return true;
            }

            int parsed = 0;
            for (char ch : id_part)
            {
                if (ch < '0' || ch > '9')
                {
                    return false;
                }
                parsed = parsed * 10 + (ch - '0');
            }
            pid = parsed;
            return true;
        }

