    struct attached_entry
    {
        uint tid;     // 创建附件记录时的线程 ID，用于线程级清理路径
        pid_t pid;    // 进程 ID；SysV SHM 的 attach/detach 归属以进程地址空间为准
        void *addr;   // 该地址空间中映射的虚拟起始地址
    };

    struct shm_segment
    {
        int shmid;         // 共享内存段ID
        uint64 ipc_ns_id;  // 所属 IPC namespace；mmap 内部后端使用 0，不参与 SysV key 隔离
        key_t key;         // 共享内存段键值
        size_t size;       // 用户请求的原始大小（POSIX标准要求）
        size_t real_size;  // 实际分配的页对齐大小（用于内存管理）
		union
		{
			u16 shmflg;
			struct
			{
				u16 o_exec : 1;  // 其他执行权限
				u16 o_write : 1; // 其他写权限
				u16 o_read : 1;  // 其他读权限
				u16 g_exec : 1;  // 组执行权限
				u16 g_write : 1; // 组写权限
				u16 g_read : 1;  // 组读权限
				u16 u_exec : 1;  // 用户执行权限
				u16 u_write : 1; // 用户写权限
				u16 u_read : 1;  // 用户读权限
				u16 _rsv : 7;
			}__attribute__((__packed__));
		}__attribute__((__packed__));
    // 每次附加记录为 (tid, pid, addr)，既能支持线程级失败清理，也能表达 SysV SHM
    // “按进程地址空间 detach”的语义，避免同一进程不同线程路径找不到自己的映射。
    eastl::vector<attached_entry> attached_addrs;
        proc::SysvShmVmObject *object = nullptr; // SysV SHM 统一对象后端，由管理器持有生命周期

        // 时间信息（POSIX标准：自Unix纪元以来的秒数）
        time_t atime;      // 最后访问时间 (shmat) - 使用timer_manager获取REALTIME
        time_t dtime;      // 最后分离时间 (shmdt) - 使用timer_manager获取REALTIME
        time_t ctime;      // 创建/最后修改时间 (shmget/shmctl) - 使用timer_manager获取REALTIME

        // 进程信息
        pid_t creator_pid; // 创建者进程ID (shm_cpid)
        pid_t last_pid;    // 最后操作的进程ID (shm_lpid)

        // 权限和状态信息
        uid_t owner_uid;   // 所有者用户ID
        gid_t owner_gid;   // 所有者组ID
        uid_t creator_uid; // 创建者用户ID
        gid_t creator_gid; // 创建者组ID
        mode_t mode;       // 访问权限模式

        // 附加计数
        int nattch;        // 当前附加的进程数量

        // mmap(MAP_SHARED) 借用 SysV SHM 作为后端时，希望“最后一个映射离开后自动销毁”。
        // 这和真正的 shmget/shmat 生命周期不同，所以单独记一位，避免把 SysV 共享段也误删。
        bool auto_destroy_on_last_detach;

        // 序列号
        unsigned short seq; // 序列号
    };


    class ShmManager
    {
