        eastl::unordered_map<uint64, proc::VmObject *> *registered_objects;
        size_t shmmax_limit; // /proc/sys/kernel/shmmax，可由 LTP save_restore 临时调整
        int shmmni_limit;    // /proc/sys/kernel/shmmni，限制系统共享段数量

