	struct tm
	{
		int tm_sec;			///< 秒 [0-60] (允许1个闰秒)
		int tm_min;			///< 分 [0-59]
		int tm_hour;		///< 时 [0-23]
		int tm_mday;		///< 日 [1-31]
		int tm_mon;			///< 月 [0-11] (0表示1月)
		int tm_year;		///< 年份减去1900
		int tm_wday;		///< 星期几 [0-6] (0表示星期日)
		int tm_yday;		///< 年内天数 [0-365]
		int tm_isdst;		///< 夏令时标志 [-1/0/1]

		// 扩展字段（GNU兼容）
